private async send(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: Notification['priority'];
  userId?: string;
  metadata?: Record<string, string>;
}): Promise<Notification | null> {
  // Check user preferences before sending (all channels)
  if (this.preferencesService && params.userId) {
    if (!this.preferencesService.shouldSend(params.userId, params.channel, params.type)) {
      this.logger.info(`Notification ${params.type} suppressed for user ${params.userId} by preferences`);
      this.historyService?.record({
        notificationId: generateNotificationId(),
        recipient: params.recipient,
        userId: params.userId,
        channel: params.channel,
        type: params.type,
        subject: params.subject,
        status: 'suppressed',
        priority: params.priority,
        timestamp: new Date(),
        metadata: params.metadata,
      });
      return null;
    }
  }

  const notification: Notification = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority,
    status: 'pending',
    sentAt: new Date(),
    metadata: params.metadata,
  };

  const adapter = this.adapters.get(params.channel);
  if (adapter) {
    const result = await adapter.send({
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: params.priority,
      metadata: params.metadata,
    });
    notification.status = result.success ? 'sent' : 'failed';
    if (!result.success) {
      this.logger.error(`Failed to send notification ${notification.id}: ${result.errorMessage ?? 'unknown error'}`);
    }
  } else {
    this.logger.warn(`No adapter registered for channel: ${params.channel}. Notification ${notification.id} stored as pending.`);
  }

  this.notifications.push(notification);
  this.logger.info(`Notification ${notification.id} [${notification.status}] to ${params.recipient}`);

  this.historyService?.record({
    notificationId: notification.id,
    recipient: params.recipient,
    userId: params.userId,
    channel: params.channel,
    type: params.type,
    subject: params.subject,
    status: notification.status,
    errorMessage: notification.status === 'failed' ? 'Adapter delivery failed' : undefined,
    priority: params.priority,
    timestamp: notification.sentAt,
    metadata: params.metadata,
  });

  return notification;
}

