  recipient: string;
  subject: string;
  body: string;
  priority: Notification['priority'];
  userId?: string;
  metadata?: Record<string, string>;
}): Promise<Notification | null> {
  const queueKey = params.userId ?? params.recipient;
  const previous = this.sendQueues.get(queueKey) ?? Promise.resolve();

  const current = previous.then(() => this.deliverNotification(params));

  // Store the chain; swallow errors so one failure doesn't block future sends
  this.sendQueues.set(queueKey, current.then(() => {}, () => {}));

  return current;
}

